<?php

declare(strict_types=1);

namespace SkyFi\Reports\QueryBuilders;

use SkyFi\Reports\Contracts\ReportQueryBuilderContract;
use SkyFi\Reports\DTOs\ReportRequest;

final class ReportQueryBuilder implements ReportQueryBuilderContract
{
    public function build(ReportRequest $request, bool $export = false): array
    {
        $definition = $this->definition($request->reportKey);
        $where = $definition['where'] ?? ['1=1'];
        $params = [];
        $filters = $definition['filters'] ?? [];
        foreach ($request->filters as $key => $value) {
            if ($value === '' || $value === null || !isset($filters[$key])) continue;
            $column = $filters[$key];
            if ($key === 'date_from') { $where[] = "{$column} >= :date_from"; $params['date_from'] = $value; }
            elseif ($key === 'date_to') { $where[] = "{$column} < DATE_ADD(:date_to, INTERVAL 1 DAY)"; $params['date_to'] = $value; }
            elseif ($key === 'region') { $where[] = "{$column} = :region"; $params['region'] = $value; }
            else { $where[] = "{$column} = :{$key}"; $params[$key] = (int)$value ?: $value; }
        }
        $sql = str_replace('{{where}}', implode(' AND ', $where), $definition['sql']);
        $countSql = 'SELECT COUNT(*) FROM (' . $sql . ') report_count';
        $allowed = array_column($definition['columns'], 'key');
        if ($request->sortBy !== null && in_array($request->sortBy, $allowed, true)) {
            $sql .= ' ORDER BY `' . $request->sortBy . '` ' . strtoupper($request->sortDirection);
        } elseif (isset($definition['order'])) $sql .= ' ORDER BY ' . $definition['order'];
        if (!$export) {
            $sql .= ' LIMIT :report_limit OFFSET :report_offset';
            $params['report_limit'] = $request->perPage;
            $params['report_offset'] = ($request->page - 1) * $request->perPage;
        }
        return ['sql'=>$sql,'count_sql'=>$countSql,'params'=>$params,'columns'=>$definition['columns']];
    }

