            'network.router-health'=>['sql'=>'SELECT r.name router,r.host,r.last_connection_status status,h.cpu_usage_percent,ROUND((1-h.memory_free_bytes/NULLIF(h.memory_total_bytes,0))*100,2) memory_usage_percent,h.uptime,h.checked_at recorded_at FROM mikrotik_routers r LEFT JOIN mikrotik_router_health_snapshots h ON h.router_id=r.id AND h.id=(SELECT MAX(h2.id) FROM mikrotik_router_health_snapshots h2 WHERE h2.router_id=r.id) WHERE {{where}}','where'=>['r.deleted_at IS NULL'],'filters'=>['date_from'=>'h.checked_at','date_to'=>'h.checked_at','status'=>'r.last_connection_status'],'columns'=>$c([['router','Router'],['host','Host'],['status','Status'],['cpu_usage_percent','CPU %','number'],['memory_usage_percent','Memory %','number'],['uptime','Uptime'],['recorded_at','Observed','date']])],
            'network.infrastructure-capacity'=>['sql'=>'SELECT ps.name pop_site,t.name tower,COUNT(DISTINCT s.id) sectors,COUNT(DISTINCT nd.id) devices,COUNT(DISTINCT cn.id) active_connections FROM pop_sites ps LEFT JOIN towers t ON t.pop_site_id=ps.id AND t.deleted_at IS NULL LEFT JOIN sectors s ON s.tower_id=t.id AND s.deleted_at IS NULL LEFT JOIN network_devices nd ON nd.pop_site_id=ps.id AND nd.deleted_at IS NULL LEFT JOIN connections cn ON cn.pop_site_id=ps.id AND cn.status=\'active\' AND cn.deleted_at IS NULL WHERE {{where}} GROUP BY ps.id,ps.name,t.id,t.name','where'=>['ps.deleted_at IS NULL'],'filters'=>['pop_site_id'=>'ps.id','tower_id'=>'t.id','status'=>'ps.status'],'columns'=>$c([['pop_site','POP site'],['tower','Tower'],['sectors','Sectors','number'],['devices','Devices','number'],['active_connections','Active connections','number']])],
            'network.pppoe-sessions'=>['sql'=>"SELECT DATE_FORMAT(s.started_at,'%Y-%m-%d') period,COUNT(*) sessions,SUM(s.bytes_in) bytes_in,SUM(s.bytes_out) bytes_out,AVG(s.uptime_seconds) average_uptime_seconds FROM pppoe_session_history s JOIN pppoe_accounts a ON a.id=s.account_id WHERE {{where}} GROUP BY period",'where'=>['1=1'],'filters'=>['date_from'=>'s.started_at','date_to'=>'s.started_at','customer_id'=>'a.customer_id','status'=>'a.status'],'columns'=>$c([['period','Day'],['sessions','Sessions','number'],['bytes_in','Bytes in','number'],['bytes_out','Bytes out','number'],['average_uptime_seconds','Avg uptime','number']]),'order'=>'period ASC'],
            'network.hotspot-sessions'=>['sql'=>"SELECT DATE_FORMAT(s.started_at,'%Y-%m-%d') period,COUNT(*) sessions,SUM(s.bytes_in) bytes_in,SUM(s.bytes_out) bytes_out,AVG(s.uptime_seconds) average_uptime_seconds FROM hotspot_session_history s JOIN hotspot_users u ON u.id=s.hotspot_user_id WHERE {{where}} GROUP BY period",'where'=>['1=1'],'filters'=>['date_from'=>'s.started_at','date_to'=>'s.started_at','customer_id'=>'u.customer_id','status'=>'u.status'],'columns'=>$c([['period','Day'],['sessions','Sessions','number'],['bytes_in','Bytes in','number'],['bytes_out','Bytes out','number'],['average_uptime_seconds','Avg uptime','number']]),'order'=>'period ASC'],
            'network.bandwidth-usage'=>['sql'=>"SELECT DATE_FORMAT(s.checked_at,'%Y-%m-%d %H:00') period,SUM(s.rx_bps) rx_bps,SUM(s.tx_bps) tx_bps,SUM(s.rx_bytes) rx_bytes,SUM(s.tx_bytes) tx_bytes FROM monitoring_interface_snapshots s WHERE {{where}} GROUP BY period",'where'=>['1=1'],'filters'=>['date_from'=>'s.checked_at','date_to'=>'s.checked_at'],'columns'=>$c([['period','Period'],['rx_bps','Download bps','number'],['tx_bps','Upload bps','number'],['rx_bytes','Downloaded bytes','number'],['tx_bytes','Uploaded bytes','number']]),'order'=>'period ASC'],
            'field.installation-success-rate'=>['sql'=>"SELECT DATE_FORMAT(w.created_at,'%Y-%m') period,COUNT(*) installations,SUM(w.status='completed') successful,SUM(w.status='failed') failed,ROUND(SUM(w.status='completed')*100/NULLIF(SUM(w.status IN ('completed','failed')),0),2) success_rate FROM work_orders w JOIN customers c ON c.id=w.customer_id WHERE {{where}} GROUP BY period",'where'=>['w.deleted_at IS NULL',"w.type='installation'"],'filters'=>['date_from'=>'w.created_at','date_to'=>'w.created_at','customer_id'=>'w.customer_id','region'=>'c.city','pop_site_id'=>'w.pop_site_id','tower_id'=>'w.tower_id','technician_id'=>'w.assigned_technician_id','status'=>'w.status'],'columns'=>$c([['period','Period'],['installations','Installations','number'],['successful','Successful','number'],['failed','Failed','number'],['success_rate','Success %','number']]),'order'=>'period ASC'],
            'field.technician-productivity'=>['sql'=>"SELECT u.name technician,t.employee_code,COUNT(w.id) assigned_jobs,SUM(w.status='completed') completed_jobs,ROUND(AVG(CASE WHEN w.completed_at IS NOT NULL THEN TIMESTAMPDIFF(MINUTE,w.started_at,w.completed_at)/60 END),2) average_hours FROM technicians t JOIN users u ON u.id=t.user_id LEFT JOIN work_orders w ON w.assigned_technician_id=t.id AND w.deleted_at IS NULL WHERE {{where}} GROUP BY t.id,u.name,t.employee_code",'where'=>['t.deleted_at IS NULL'],'filters'=>['date_from'=>'w.created_at','date_to'=>'w.created_at','technician_id'=>'t.id','status'=>'w.status'],'columns'=>$c([['technician','Technician'],['employee_code','Employee code'],['assigned_jobs','Assigned','number'],['completed_jobs','Completed','number'],['average_hours','Average hours','number']]),'order'=>'completed_jobs DESC'],
            'field.average-completion-time'=>['sql'=>"SELECT DATE_FORMAT(w.completed_at,'%Y-%m') period,w.type,COUNT(*) completed_jobs,ROUND(AVG(TIMESTAMPDIFF(MINUTE,w.started_at,w.completed_at))/60,2) average_hours FROM work_orders w JOIN customers c ON c.id=w.customer_id WHERE {{where}} GROUP BY period,w.type",'where'=>['w.deleted_at IS NULL','w.started_at IS NOT NULL','w.completed_at IS NOT NULL'], 'filters'=>['date_from'=>'w.completed_at','date_to'=>'w.completed_at','customer_id'=>'w.customer_id','region'=>'c.city','pop_site_id'=>'w.pop_site_id','tower_id'=>'w.tower_id','technician_id'=>'w.assigned_technician_id','status'=>'w.status'],'columns'=>$c([['period','Period'],['type','Work type'],['completed_jobs','Completed','number'],['average_hours','Average hours','number']]),'order'=>'period ASC'],
        ];
        return $definitions[$key];
    }
}
